{"report_type": "HTML", "html": "<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8" />
<style>
  @page { margin: 12mm 14mm 8mm 14mm; }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: Arial, Helvetica, sans-serif; font-size: 9pt; color: #1a1a2e; background: #fff; }
  .page { max-width: 820px; margin: 0 auto; padding: 0; }
  .hotel-logo { max-height: 70px; max-width: 140px; }
  .logo-box { display: inline-block; width: 46px; height: 46px; background: #1a1a2e; color: #fff; font-size: 16pt; font-weight: 700; text-align: center; line-height: 46px; border-radius: 5px; }
  .hotel-name { font-size: 14pt; font-weight: 700; color: #1a1a2e; }
  .hotel-sub { font-size: 7.5pt; color: #6b7280; margin-top: 2px; line-height: 1.5; }
  .doc-title { font-size: 13pt; font-weight: 700; color: #1a1a2e; }
  .doc-subtitle { font-size: 7pt; color: #6b7280; text-transform: uppercase; letter-spacing: 0.8px; margin-top: 2px; }
  .doc-ref { font-size: 8pt; color: #6b7280; margin-top: 6px; line-height: 1.7; }
  .doc-ref strong { color: #374151; }
  .header-divider { border: none; border-top: 2px solid #1a1a2e; margin: 14px 0 16px; }
  .section-title { font-size: 7.5pt; font-weight: 700; color: #fff; text-transform: uppercase; letter-spacing: 0.6px; background: #1a1a2e; padding: 6px 9px; margin-top: 14px; margin-bottom: 8px; }
  .info-table { width: 100%; border-collapse: collapse; margin-bottom: 4px; }
  .info-table td { padding: 4px 8px; font-size: 9pt; border-bottom: 1px solid #f1f5f9; vertical-align: middle; white-space: nowrap; }
  .info-table tr:last-child td { border-bottom: none; }
  .info-key { width: 22%; color: #1a1a2e; font-weight: 700; }
  .info-val { width: 28%; color: #1a1a2e; font-weight: 400; }
  .stats-table { width: 100%; border-collapse: collapse; margin-bottom: 4px; }
  .stats-table td { padding: 6px 10px; font-size: 9pt; border-bottom: 1px solid #f1f5f9; text-align: center; }
  .stats-table thead th { background: #1a1a2e; color: #fff; padding: 6px 10px; font-size: 7pt; font-weight: 700; text-transform: uppercase; }
  .data-table { width: 100%; border-collapse: collapse; font-size: 8pt; margin-bottom: 4px; }
  .data-table thead tr { background: #1a1a2e; color: #fff; }
  .data-table thead th { padding: 6px 7px; text-align: left; font-size: 7pt; font-weight: 700; text-transform: uppercase; letter-spacing: 0.3px; }
  .data-table thead th.num { text-align: right; }
  .data-table tbody tr:nth-child(even) { background: #f9fafb; }
  .data-table tbody td { padding: 6px 7px; border-bottom: 1px solid #f1f5f9; color: #374151; }
  .data-table tbody td.num { text-align: right; }
  .data-table tfoot tr { border-top: 2px solid #1a1a2e; background: #f9fafb; }
  .data-table tfoot td { padding: 7px 7px; font-weight: 700; color: #1a1a2e; }
  .footer-divider { border: none; border-top: 1px solid #e5e7eb; margin: 20px 0 12px; }
  .footer-note { font-size: 7pt; color: #9ca3af; line-height: 1.7; }
  .footer-company { font-size: 9pt; font-weight: 700; color: #1a1a2e; }
  .footer-date { font-size: 7pt; color: #9ca3af; margin-top: 2px; }
  .sig-line { margin-top: 16px; border-top: 1px solid #e5e7eb; padding-top: 5px; font-size: 7pt; color: #9ca3af; text-align: center; }
</style>
</head>
<body>
<div class="page">

  <!-- HEADER -->
  <table width="100%" cellpadding="0" cellspacing="0">
    <tr>
      <td width="55%" valign="top">
        <table cellpadding="0" cellspacing="0">
          <tr>
            <td style="padding-right:10px;" valign="middle">
              {% if hotel_logo %}<img src="{{ hotel_logo }}" alt="{{ company }}" class="hotel-logo" />
              {% else %}<div class="logo-box">{{ (company or 'H')[:1] }}</div>{% endif %}
            </td>
            <td valign="middle">
              <div class="hotel-name">{{ company }}</div>
              <div class="hotel-sub">
                {% if hotel_tagline %}{{ hotel_tagline }}<br>{% endif %}
                {% if hotel_address %}{{ hotel_address }}<br>{% endif %}
                {% if hotel_phone %}{{ hotel_phone }}{% if hotel_email %} &middot; {% endif %}{% endif %}
                {% if hotel_email %}{{ hotel_email }}{% endif %}
              </div>
            </td>
          </tr>
        </table>
      </td>
      <td valign="top" align="right">
        <div class="doc-title">Kitchen Order Report</div>
        <div class="doc-subtitle">Ticket Volume &amp; Status</div>
        <div class="doc-ref">
          <strong>Period:</strong> {{ filters.date_from }} &mdash; {{ filters.date_to }}<br>
          <strong>Generated:</strong> {{ generated_at }}
        </div>
      </td>
    </tr>
  </table>
  <hr class="header-divider" />

  <!-- FILTERS -->
  <div class="section-title">Report Filters</div>
  <table class="info-table" cellpadding="0" cellspacing="0">
    <colgroup><col style="width:22%" /><col style="width:28%" /><col style="width:22%" /><col style="width:28%" /></colgroup>
    <tr>
      <td class="info-key">Date From</td><td class="info-val">{{ filters.date_from }}</td>
      <td class="info-key">Date To</td><td class="info-val">{{ filters.date_to }}</td>
    </tr>
    <tr>
      <td class="info-key">Status</td><td class="info-val">{{ filters.status or 'All' }}</td>
      <td class="info-key">Source</td><td class="info-val">{{ filters.source or 'All' }}</td>
    </tr>
    <tr>
      <td class="info-key">Station</td><td class="info-val">{{ filters.station or 'All' }}</td>
      <td class="info-key">POS Profile</td><td class="info-val">{{ filters.pos_profile or 'All' }}</td>
    </tr>
  </table>

  <!-- SUMMARY -->
  <div class="section-title">Summary</div>
  <table class="stats-table" cellpadding="0" cellspacing="0">
    <thead>
      <tr>
        <th>Total Tickets</th><th>Pending</th><th>In Progress</th>
        <th>Ready</th><th>Delayed</th><th>Served</th><th>Total Items</th><th>Avg Stage (min)</th>
      </tr>
    </thead>
    <tbody>
      <tr>
        <td style="font-weight:700;">{{ summary.total_tickets }}</td>
        <td style="color:#d97706;">{{ summary.pending_count }}</td>
        <td style="color:#2563eb;">{{ summary.in_progress_count }}</td>
        <td style="color:#15803d;">{{ summary.ready_count }}</td>
        <td style="color:#dc2626;">{{ summary.delayed_count }}</td>
        <td style="color:#6b7280;">{{ summary.served_count }}</td>
        <td style="font-weight:600;">{{ summary.total_items }}</td>
        <td style="color:#6b7280;">{{ summary.avg_stage_minutes }}</td>
      </tr>
    </tbody>
  </table>

  <!-- ORDERS TABLE -->
  <div class="section-title">Kitchen Orders &mdash; {{ rows | length }} ticket(s)</div>
  {% if rows %}
  <table class="data-table" cellpadding="0" cellspacing="0">
    <thead>
      <tr>
        <th>#</th><th>Ticket</th><th>POS Invoice</th>
        <th>Table / Room</th><th>Source</th><th>Station</th>
        <th>Status</th><th class="num">Items</th><th class="num">Age (min)</th>
      </tr>
    </thead>
    <tbody>
      {% for row in rows %}
      <tr>
        <td style="color:#9ca3af;">{{ loop.index }}</td>
        <td style="font-weight:600;font-size:7.5pt;">{{ row.ticket_name }}</td>
        <td style="font-size:7.5pt;color:#6b7280;">{{ row.pos_invoice or '&mdash;' }}</td>
        <td>{{ row.table_or_room or '&mdash;' }}</td>
        <td style="color:#6b7280;">{{ row.source or '&mdash;' }}</td>
        <td style="color:#6b7280;">{{ row.chef_station or '&mdash;' }}</td>
        <td style="font-weight:600;
          {% if row.status == 'Delayed' %}color:#dc2626;
          {% elif row.status == 'Ready' %}color:#15803d;
          {% elif row.status == 'In Progress' %}color:#2563eb;
          {% elif row.status == 'Pending' %}color:#d97706;
          {% else %}color:#6b7280;{% endif %}">
          {{ row.status }}
        </td>
        <td class="num">{{ row.total_qty }}</td>
        <td class="num" style="{% if row.age_minutes | int > 35 %}color:#dc2626;font-weight:600;{% endif %}">
          {{ row.age_minutes }}
        </td>
      </tr>
      {% endfor %}
    </tbody>
    <tfoot>
      <tr>
        <td colspan="7">Total</td>
        <td class="num">{{ summary.total_items }}</td>
        <td></td>
      </tr>
    </tfoot>
  </table>
  {% else %}
  <p style="padding:14px;color:#9ca3af;font-size:8pt;border:1px dashed #e5e7eb;">No kitchen orders found for the selected filters.</p>
  {% endif %}

  <!-- FOOTER -->
  <hr class="footer-divider" />
  <table width="100%" cellpadding="0" cellspacing="0">
    <tr>
      <td width="60%" valign="bottom">
        <div class="footer-note">
          This report is generated by the {{ company }} Property Management System.<br>
          <strong style="color:#374151;">Period: {{ filters.date_from }} to {{ filters.date_to }}</strong>
        </div>
      </td>
      <td valign="bottom" align="right">
        <div class="footer-company">{{ company }}</div>
        <div class="footer-date">{{ generated_at }}</div>
        <div class="sig-line">Authorised Signature</div>
      </td>
    </tr>
  </table>
</div>
</body>
</html>"}
